#include <bits/stdc++.h>

using namespace std;

void dfs(int node, vector < vector < int >> & adj, vector < int > & a, int & maxDisp, int maxWealth) {
    maxDisp = max(maxDisp, maxWealth - a[node]);

    maxWealth = max(maxWealth, a[node]);

    for (int ne: adj[node]) {
        dfs(ne, adj, a, maxDisp, maxWealth);
    }
}

int main() {
    int n;
    cin >> n;

    vector < int > a(n + 1);
    vector < vector < int >> adj(n + 1);

    for (int i = 0; i < n; i++) {
        cin >> a[i + 1];
    }
    int start;
    for (int i = 1; i < n + 1; i++) {
        int q;
        cin >> q;
        if (q == -1) {
            start = i;
        } else {
            adj[q].push_back(i);
        }
    }

    int maxDisp = INT_MIN;
    dfs(start, adj, a, maxDisp, a[start]);
    cout << maxDisp << endl;

    return 0;
}
